import React, { useState } from 'react'
import { Link } from 'react-router-dom'

import './Header.css'


function Header() {
  const wishcounter = 5;
  const cartcounter = 3

  const [barsMenu, setBarsMenu] = useState(false);
  const handleClick = () => setBarsMenu(!barsMenu)

  return (
    <div className={barsMenu ? 'nav responsive' : 'nav'}>

      <div className='nav-title'>
        <Link to='/'>My Furniture</Link>
      </div>

      <div className='nav-menu '>
        <Link to='/login'>My Account</Link>
        <Link to='/wishlist'>Wishlist <span>({wishcounter})</span></Link>
        <Link to='/contact'>Contact</Link>
        <Link to='/cart'>Cart <span>({cartcounter})</span></Link>
      </div>

      <button type='button' className='bars-icon' onClick={handleClick}>
        {barsMenu ? <i className='fa fa-close'/> : <i className='fa fa-bars'/>}
      </button>

    </div>
  )
}

export default Header;
